class Solution {
public:
    int lengthAfterTransformations(string s, int t, vector<int>& nums) {
        vector<int> cycleLengths(26, 0);
        for (int i = 0; i < 26; ++i) {
            int nextChar = i;
            for (int j = 0; j < 26; ++j) {
                nextChar = (nextChar + nums[i]) % 26;
            }
            cycleLengths[i] = (nextChar - i + 26) % 26;
            if (cycleLengths[i] == 0) cycleLengths[i] = 26;
        }

        int length = 0;
        for (char c : s) {
            length = (length + cycleLengths[c - 'a']) % (1e9 + 7);
        }

        return (int)((long long)length * t % (1e9 + 7));
    }
};
